import React, { useState, useEffect } from 'react';
import { FaRobot, FaCoins, FaArrowRight } from 'react-icons/fa';

const Marketplace = () => {
  const [agents, setAgents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Mock data - in real app, fetch from API
    const mockAgents = [
      {
        id: 1,
        name: 'Text Summarizer Pro',
        description: 'Advanced AI for summarizing long texts into concise, readable formats.',
        category: 'Text Analysis',
        price: 0.5,
        rating: 4.8
      },
      {
        id: 2,
        name: 'Code Generator',
        description: 'Generate high-quality code snippets in multiple programming languages.',
        category: 'Code Generation',
        price: 1.2,
        rating: 4.9
      },
      {
        id: 3,
        name: 'Content Writer',
        description: 'Create engaging blog posts, articles, and marketing content.',
        category: 'Content Creation',
        price: 0.8,
        rating: 4.7
      },
      {
        id: 4,
        name: 'Data Analyzer',
        description: 'Process and analyze datasets to extract meaningful insights.',
        category: 'Data Processing',
        price: 1.5,
        rating: 4.6
      }
    ];
    setAgents(mockAgents);
    setLoading(false);
  }, []);

  const handleUseService = (agent) => {
    // In real app, navigate to task submission with selected agent
    alert(`Selected ${agent.name} for ${agent.price} ALGO`);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading agents...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 p-4">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">AI Agent Marketplace</h1>
          <p className="text-xl text-gray-600">Choose from our collection of specialized AI agents</p>
        </div>

        {/* Agent Grid */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {agents.map(agent => (
            <div key={agent.id} className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow">
              <div className="flex items-center mb-4">
                <div className="bg-purple-100 w-12 h-12 rounded-lg flex items-center justify-center mr-4">
                  <FaRobot className="text-purple-600 text-xl" />
                </div>
                <div>
                  <h3 className="text-lg font-semibold text-gray-900">{agent.name}</h3>
                  <span className="text-sm text-gray-500">{agent.category}</span>
                </div>
              </div>

              <p className="text-gray-600 mb-4 line-clamp-3">{agent.description}</p>

              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center">
                  <FaCoins className="text-yellow-500 mr-1" />
                  <span className="font-semibold text-gray-900">{agent.price} ALGO</span>
                </div>
                <div className="flex items-center">
                  <span className="text-yellow-500 mr-1">★</span>
                  <span className="text-sm text-gray-600">{agent.rating}</span>
                </div>
              </div>

              <button
                onClick={() => handleUseService(agent)}
                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 text-white py-3 px-4 rounded-lg font-medium hover:from-blue-700 hover:to-purple-700 transition-all transform hover:scale-105 inline-flex items-center justify-center"
              >
                Use Service
                <FaArrowRight className="ml-2" />
              </button>
            </div>
          ))}
        </div>

        {/* Empty State */}
        {agents.length === 0 && (
          <div className="text-center py-16">
            <FaRobot className="text-gray-400 text-6xl mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No agents available</h3>
            <p className="text-gray-600">Check back later for new AI agents</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Marketplace;
